function solve(nums) {
    let total_x_sum = 0;
    const n = nums.length;

    if (n <= 1) {
        return 0;
    }

    // We iterate through all adjacent pairs (nums[i], nums[i+1]).
    // If nums[i] > nums[i+1], we have a drop that needs correction.
    // The minimum total amount of increase (sum of x) required is exactly 
